SELECT h.*, u.nickname AS publisher_nickname FROM help_request h
LEFT JOIN sys_user u ON h.user_id = u.id

    AND h.status = #{status}
    AND h.user_id = #{userId}

ORDER BY h.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM help_request h

    AND h.status = #{status}
    AND h.user_id = #{userId}
